from django.db import models
from django.apps import apps
from django.conf import settings

# Create a test app for the model
class TestAppConfig:
    name = 'test_app'
    label = 'test_app'

# Register the test app
apps.populate([TestAppConfig])

class MyModel(models.Model):
    my_datetime_field = models.DateTimeField()

# Ensure the test app is included in INSTALLED_APPS
settings.INSTALLED_APPS = ['test_app']

@override_settings(USE_TZ=True, TIME_ZONE='Europe/Paris', DATABASES={
    'default': {
        'ENGINE': 'django.db.backends.mysql',
        'OPTIONS': {
            'read_default_file': '....cnf',
        },
        'TIME_ZONE': 'Europe/Paris',
    },
    'legacy': {
        'ENGINE': 'django.db.backends.mysql',
        'OPTIONS': {
            'read_default_file': '....cnf',
        },
        'TIME_ZONE': 'Europe/Paris',
    },
})
class TimezoneBugTests(SimpleTestCase):
    def setUp(self):
        # Create a datetime object in the 'Europe/Paris' timezone
        self.test_datetime = timezone.make_aware(datetime(2017, 7, 6, 20, 50))

        # Populate the database with a test entry
        MyModel.objects.create(my_datetime_field=self.test_datetime)

    def test_date_lookup_exposes_timezone_bug(self):
        # Perform a date lookup using the __date filter
        result = MyModel.objects.filter(my_datetime_field__date=self.test_datetime.date()).exists()

        # Assert that the result is False, indicating the bug is present
        self.assertFalse(result)  # BUG: this behavior is incorrect but currently happens due to the bug
```

